$ErrorActionPreference='Stop'
$root=Split-Path -Parent $PSScriptRoot;$ff=Join-Path $root 'node_modules\ffmpeg-static\ffmpeg.exe';$dir=Join-Path $root 'video-jury';$seg=Join-Path $dir 'segments';New-Item -ItemType Directory -Force $seg|Out-Null
$names=@('01-dashboard','02-probleme','03-matching','04-clients','05-fournisseur','06-ia','07-marketplace','08-business','09-pilotage','10-avantage','11-partenaires','12-impact')
for($i=0;$i -lt $names.Count;$i++){$img=Join-Path $dir ($names[$i]+'.png');$aud=Join-Path $dir ('voice\{0:D2}.mp3' -f ($i+1));$clip=Join-Path $seg ('{0:D2}.mp4' -f ($i+1));& $ff -y -loop 1 -framerate 25 -i $img -i $aud -filter_complex "[0:v]scale=1440:900:force_original_aspect_ratio=decrease,pad=1440:900:(ow-iw)/2:(oh-ih)/2,format=yuv420p[v];[1:a]apad,atrim=0:9,asetpts=PTS-STARTPTS[a]" -map '[v]' -map '[a]' -t 9 -c:v libx264 -preset medium -crf 20 -c:a aac -b:a 144k -movflags +faststart $clip;if($LASTEXITCODE-ne 0){throw "Échec segment $($i+1)"}}
$list=Join-Path $seg 'concat.txt';$content=$names|ForEach-Object -Begin{$i=0}-Process{$i++;"file '$((Join-Path $seg ('{0:D2}.mp4' -f $i)).Replace('\','/'))'"};[IO.File]::WriteAllLines($list,$content,[Text.UTF8Encoding]::new($false))
$out=Join-Path $root 'Waste2Cash_Demo_Jury_FR.mp4';& $ff -y -f concat -safe 0 -i $list -c copy -movflags +faststart $out;if($LASTEXITCODE-ne 0){throw 'Échec assemblage final'};Write-Output $out
